# ===== TF-IDF 計算 =====

def tokenize(text):
    """用字元 bigram 切中文，同時保留英文字母數字為整詞"""
    tokens = []
    buf = ''
    for ch in text:
        if ch.isascii() and ch.isalnum():
            buf += ch.lower()
        else:
            if buf:
                tokens.append(buf)
                buf = ''
            if '\u4e00' <= ch <= '\u9fff':  # CJK
                tokens.append(ch)
    if buf:
        tokens.append(buf)
    # bigrams from CJK chars
    cjk = [t for t in tokens if len(t) == 1 and '\u4e00' <= t <= '\u9fff']
    bigrams = [cjk[i]+cjk[i+1] for i in range(len(cjk)-1)]
    return tokens + bigrams

def card_text(c):
    return f"{c['title']} {c['problem']} {c['solution']} {c['context']} {c.get('warning','')}"

# Build corpus
corpus = [tokenize(card_text(c)) for c in CARDS]

# Document frequency
df = Counter()
for doc in corpus:
    for tok in set(doc):
        df[tok] += 1

N = len(corpus)

# Build vocabulary (top tokens by df, skip too rare or too common)
vocab = [tok for tok, freq in df.items() if 2 <= freq <= N*0.8]
vocab.sort()
vocab_idx = {tok: i for i, tok in enumerate(vocab)}
V = len(vocab)
print(f"Vocabulary size: {V}")

# TF-IDF vectors
vectors = []
for doc in corpus:
    tf = Counter(doc)
    vec = [0.0] * V
    for tok, i in vocab_idx.items():
        if tok in tf:
            vec[i] = (1 + math.log(tf[tok])) * math.log(N / df[tok])
    # L2 normalize
    norm = math.sqrt(sum(x*x for x in vec)) or 1
    vec = [round(x/norm, 5) for x in vec]
    # Sparse: only keep non-zero
    sparse = {str(i): v for i, v in enumerate(vec) if v > 0}
    vectors.append(sparse)

# Output
output = {
    "vocab_size": V,
    "cards": [],
}
for i, c in enumerate(CARDS):
    c_out = {**c, "id": i+1, "created": "2026-03-30", "vec": vectors[i]}
    output["cards"].append(c_out)

with open("cards-with-vectors.json", "w", encoding="utf-8") as f:
    json.dump(output, f, ensure_ascii=False, indent=None)

# Stats
non_zero_avg = sum(len(v) for v in vectors) / len(vectors)
print(f"Cards: {len(CARDS)}")
print(f"Avg non-zero dims per card: {non_zero_avg:.0f}")
total_bytes = len(json.dumps(output, ensure_ascii=False))
print(f"JSON size: {total_bytes/1024:.0f} KB")
print("✅ cards-with-vectors.json generated")
